    expect(context.notifyWebviewReady).toHaveBeenCalledTimes(1);
    expect(context.setWebviewReadyNotified).toHaveBeenCalledWith(true);
    expect(context.setWebviewReadyNotified).toHaveBeenCalledTimes(1);
